Bash(# Nosana is a TypeScript SDK for Solana, not a CLI. Let's test it programmatically.
node -e "
const { createNosanaClient, NosanaNetwork } = require\('@nosana/kit'\);
const client = createNosanaClient\(NosanaNetwork.DEVNET\);
console.log\('Nosana client created:', typeof client\);
console.log\('Methods:', Object.keys\(client\)\);

// Try to list jobs
client.jobs.all\({ limit: 3 }\).then\(jobs => {
    console.log\('Jobs found:', jobs.length\);
    if \(jobs.length > 0\) {
        console.log\('First job:', JSON.stringify\(jobs[0]\).substring\(0, 300\)\);
    }
    console.log\('NOSANA: WORKING'\);
}\).catch\(err => {
    console.log\('Nosana jobs error:', err.message\);
}\);
" 2>&1)

Bash(# Test Nosana on mainnet - just check connection, not decode all jobs
node -e "
const { createNosanaClient, NosanaNetwork } = require\('@nosana/kit'\);
const client = createNosanaClient\(NosanaNetwork.MAINNET\);
console.log\('Nosana mainnet client created'\);
console.log\('Solana RPC:', client.config.solana.rpcEndpoint\);

// Test by getting market info
client.api.getMarkets\({ limit: 2 }\).then\(markets => {
    console.log\('Markets found:', markets.length\);
    if \(markets.length > 0\) {
        console.log\('First market:', JSON.stringify\(markets[0]\).substring\(0, 200\)\);
    }
    console.log\('NOSANA API: WORKING'\);
}\).catch\(err => {
    console.log\('Markets API error:', err.message.substring\(0, 200\)\);
}\);
" 2>&1 | head -10)

Bash(# Simplified Nosana test - just verify we can connect to Solana and read state
