Bash(# Check Nosana client structure
node -e "
const { createNosanaClient, NosanaNetwork } = require\('@nosana/kit'\);
const client = createNosanaClient\(NosanaNetwork.MAINNET\);

function showMethods\(obj, prefix = ''\) {
    for \(const key of Object.keys\(obj\)\) {
        const val = obj[key];
        if \(typeof val === 'function'\) {
            console.log\(prefix + key + '\(\)'\);
        } else if \(typeof val === 'object' && val !== null && !Array.isArray\(val\) && Object.keys\(val\).length > 0\) {
            showMethods\(val, prefix + key + '.'\);
        }
    }
}
showMethods\(client\);
" 2>&1)

