const client = createNosanaClient\(NosanaNetwork.MAINNET\);

// Test API markets
client.api.markets.list\({ limit: 2 }\).then\(markets => {
    console.log\('Markets:', markets.length\);
    if \(markets.length > 0\) {
        console.log\('First:', JSON.stringify\(markets[0]\).substring\(0, 300\)\);
    }
    console.log\('NOSANA API: WORKING'\);
}\).catch\(err => {
    console.log\('Markets error:', err.message.substring\(0, 200\)\);
}\);

// Test credits balance
client.api.credits.balance\(\).then\(balance => {
    console.log\('Credits balance:', JSON.stringify\(balance\).substring\(0, 200\)\);
}\).catch\(err => {
    console.log\('Credits error:', err.message.substring\(0, 200\)\);
}\);

// List jobs
client.jobs.list\({ limit: 2 }\).then\(jobs => {
    console.log\('Jobs listed:', jobs.length\);
    console.log\('NOSANA JOBS: WORKING'\);
}\).catch\(err => {
    console.log\('Jobs error:', err.message.substring\(0, 200\)\);
}\);
" 2>&1)
